INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (1, '任天堂', 'ニンテンドウ', '任天堂株式会社は、日本の企業で主に玩具やコンピュータゲームの開発・製造・販売を行っており、京都府京都市南区に本社を置いています。\r\n同社は1889年に創業し、多くの種類の玩具を製作してきました。\r\n1970年代後期には、家庭用と業務用のコンピュータゲーム機の開発を始め、1985年に発売された『スーパーマリオブラザーズ』は世界的なヒットとなりました。\r\n任天堂のゲームソフトには、世界的に認知されている多数のキャラクターが登場しており、同社はそれらのキャラクターIPをゲーム外でも活用されています。', 'nintendo', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (2, 'ソニー・コンピュータエンタテインメント', 'ソニー・コンピュータエンタテインメント', 'ソニー・インタラクティブエンタテインメント（SIE）は、ソニーグループのビデオゲーム・デジタルエンタテインメント企業であり、2つの法人組織で構成されています。\r\n東京都港区に本社を置くSIE Inc.は、1993年に設立され、プレイステーション用ゲーム機の開発を行っていました。\r\n一方、グループ本社であるSIE LLCは、2016年にアメリカカリフォルニア州に設立され、ソニー・コーポレーション・オブ・アメリカを通じて運営されています。\r\nSIEは、PlayStation向けゲーム機のハード・ソフトの研究開発、製造、販売を行い、ビデオゲームタイトルの開発・販売も行っています。\r\n1994年以降、北米、ヨーロッパ、アジアに進出し、複数の子会社を運営しています。\r\n2018年8月までに、同社は全世界で5億2500万台以上のPlayStationコンソールを販売しています。', 'sce', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (3, 'マイクロソフト', 'マイクロソフト', 'マイクロソフトは、アメリカの大手ソフトウェア企業であり、WindowsオペレーティングシステムやMicrosoft Officeなどのソフトウェア製品を開発・販売しています。また、Xboxブランドのゲーム機や、関連するゲームソフトの開発・販売も行っています。2001年に初代Xboxを発売して以来、Xbox 360、Xbox One、Xbox Series X/Sと次々と新機種をリリースし、コンシューマーゲーム市場に参入しています。また、PCとのクロスプラットフォームに注力し、マルチプレイヤーゲームの開発・販売にも力を入れています。Microsoftは、グローバル企業として多くの事業を展開しており、ゲーム市場でも常に新しい技術やサービスを提供し、競争力を維持しています。', 'microsoft', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (4, 'セガ', 'セガ', 'セガは、日本のゲームメーカーであり、1980年代からアーケードゲーム市場に参入し、世界的な成功を収めました。代表的なアーケードゲームには、『スペースハリアー』や『アウトラン』、『バーチャファイター』などがあります。また、セガは家庭用ゲーム市場にも参入し、『メガドライブ』や『ドリームキャスト』などのゲーム機を開発・販売しました。セガの代表的なゲームタイトルには、『ソニック・ザ・ヘッジホッグ』、『ファンタシースター』、『龍が如く』などがあります。現在はセガグループの一部として、PC、スマートフォン向けのゲーム開発・配信や、ライセンスビジネスなどを展開しています。', 'sega', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (5, 'NECホームエレクトロニクス', 'NECホームエレクトロニクス', 'NECホームエレクトロニクスは、かつて日本の電機メーカーであったNECの子会社で、家庭用テレビゲーム機などの家電製品を手がけていました。代表的な製品としては、PCエンジンなどのゲーム機や、液晶テレビ、DVDプレーヤーなどがあります。PCエンジンは、1987年に発売された16ビットのゲーム機で、独自のゲームソフトライブラリーを持ち、当時の任天堂やセガとの競争に一定の成功を収めました。しかし、その後のゲーム機市場においては、任天堂やソニーなどの競合他社に押され、事業縮小を余儀なくされました。現在は、NECブランドのパソコン、サーバー、ネットワーク機器などを展開するNECプラットフォームズに吸収合併されています。', 'nec', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (6, 'SNK', 'エスエヌケー', 'SNKは、日本のゲームメーカーで、主にアーケードゲームや家庭用ゲーム機用ソフトウェアの開発・販売を手がけています。代表的な作品には、『ザ・キング・オブ・ファイターズ』、『メタルスラッグ』、『サムライスピリッツ』などがあります。また、SNKは自社開発のアーケードゲーム用ハードウェア「NEO GEO」を開発し、高性能なグラフィックと音響で話題となりました。NEO GEOは家庭用ゲーム機版も発売され、ゲーム機市場で一定の成功を収めました。現在は、SNKプレイモアとしてゲームソフトウェアの開発やライセンス事業、スマートフォン向けアプリ開発などを手がけています。', 'snk', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (7, '松下電器', 'マツシタデンキ', '松下電器産業（現・パナソニック）は、家庭用テレビゲーム機などの家電製品を手がけていました。1983年には、自社開発のゲーム機「ワンダーコンピュータ」を発売しましたが、当時の任天堂やセガとの競合には敵わず、販売不振に陥り撤退しました。その後は、家庭用ビデオゲーム機向けのゲームソフト開発や、アーケードゲームの製造販売などを手がけました。代表的な作品としては、『スーパーファミコンウォーズ』や『テトリス2＋ボンブリス』があります。しかし、1990年代後半には、不採算事業からの撤退やパソコン向け電子機器事業への注力などにより、ゲーム事業からは撤退しています。', 'panasonic', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (8, 'バンダイ', 'バンダイ', 'バンダイは、日本を代表する玩具メーカーであり、玩具やプラモデルなどのおもちゃを中心に事業展開しています。また、アニメ作品の企画・制作も手がけ、多数のヒット作品を生み出しています。ゲーム業界においては、アーケードゲームや家庭用ゲーム機向けのゲームソフトウェアの開発・販売を手がけており、代表的な作品には、『ドラゴンボールZ』シリーズや『機動戦士ガンダム』シリーズがあります。また、バンダイナムコエンターテインメント（旧ナムコ）との合併により、ゲーム事業は更に強化され、世界的に有名なゲームブランドとして知られています。', 'bandai', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (9, 'ソニー・インタラクティブエンタテインメント', 'ソニー・インタラクティブエンタテインメント', 'ソニー・インタラクティブエンタテインメント（SIE）は、ソニーグループの一部門で、PlayStationを中心とする家庭用ゲーム機の開発・販売を手がけています。また、ゲームソフトウェアの制作・販売、オンラインサービスの提供なども行っています。代表的な作品には、『グランツーリスモ』シリーズ、『ラストオブアス』シリーズ、『アンチャーテッド』シリーズなどがあり、高い評価を得ています。また、SIEは、PlayStationVRなどのVRデバイスの開発・販売も手がけており、VR技術の進化とともに、より高い没入感を持つゲームエクスペリエンスを提供しています。', 'sie', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (10, 'エニックス', 'エニックス', 'エニックスは、日本のゲームソフト開発・販売会社で、主に家庭用ゲーム機向けのゲームソフトを手がけています。代表的な作品には、『ドラゴンクエスト』シリーズがあります。『ドラゴンクエスト』は、シリーズ累計で7,000万本以上を売り上げ、日本を代表するRPG（ロールプレイングゲーム）のひとつとして知られています。また、エニックスは、スマートフォン向けのゲームアプリの開発・運営も手がけており、『ドラゴンクエスト』シリーズをはじめとした人気タイトルをスマートフォンでも楽しむことができます。エニックスは、2003年にスクウェアと合併し、スクウェアエニックスとなりました。', 'enix', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (11, 'バンプレスト', 'バンプレスト', 'バンプレストは、日本の玩具メーカーで、主にアーケードゲームや家庭用ゲーム機向けのゲームソフトを手がけています。代表的な作品には、『スーパーロボット大戦』シリーズや『ドラゴンボールZ』シリーズがあります。また、バンプレストは、アニメ・マンガ・特撮などのコンテンツを活用した玩具やグッズを多数展開しており、特に「プライズ」と呼ばれるUFOキャッチャーなどの景品を扱うビジネスが有名です。バンプレストは、2008年にナムコと合併し、バンダイナムコゲームスとなりましたが、バンプレストブランドは現在も存続しています。', 'banpresto', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (12, 'テクノスジャパン', 'テクノスジャパン', 'テクノスジャパンは、かつて存在した日本のゲーム開発会社で、代表的な作品には「くにおくんシリーズ」や「ダブルドラゴンシリーズ」があります。これらの作品は、当時のアーケードゲーム市場において大きな人気を博し、後に家庭用ゲーム機にも移植されました。また、テクノスジャパンは、スポーツゲームの分野でも多くの作品を手がけ、特にプロレスゲームの「闘魂伝承シリーズ」は、現在でも熱狂的なファンが存在しています。しかし、テクノスジャパンは1996年に倒産してしまい、現在は解散しています。しかし、その作品群は、多くのゲームファンに愛され、今もなお多くの人々に語り継がれています。', 'technosjapan', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (13, 'ハドソン', 'ハドソン', 'ハドソンは、かつて存在した日本のゲームメーカーで、代表的な作品には「ボンバーマンシリーズ」「アドベンチャーアイランドシリーズ」があります。また、任天堂の家庭用ゲーム機であるファミコンの人気を大きく支え、数多くのゲームタイトルを発売しました。ハドソンは、ゲーム業界に先駆けてオンラインゲームに注力し、「ハドソンオンラインクラブ」というオンラインサービスを展開するなど、新しい試みを積極的に行っていました。しかし、2012年にコナミデジタルエンタテインメントに吸収合併され、ハドソンの名前は消えてしまいましたが、その代表的な作品は、多くのゲームファンに愛され、今でも根強い人気を誇っています。', 'hudson', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (14, 'チュンソフト', 'チュンソフト', 'チュンソフトは、日本のゲームメーカーです。主にアドベンチャーゲームやロールプレイングゲームなどを手がけ、独自の世界観やストーリー展開が特徴的です。代表作には、「風の伝説ザナドゥ」や「聖剣伝説シリーズ」、「MOTHERシリーズ」などがあります。また、サウンドノベルというジャンルを確立し、「428 ～封鎖された渋谷で～」や「かまいたちの夜」など、多くのヒット作を生み出しています。2012年には、スパイク・チュンソフトに社名を変更し、現在はスパイク・チュンソフトブランドで、さまざまなゲームを展開しています。\r\n\r\n', 'chunsoft', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (15, 'カプコン', 'カプコン', '1979年にアイ・アール・エム（IRM）株式会社として設立されたカプコン。1981年に社名をサンビ株式会社に変更し、本社を大阪府羽曳野市に移転しました。設立者の辻本憲三は、IPMの代表取締役で、スペースインベーダーブームの際に『IPMインベーダー』を製作するが、市場飽和で10億円の在庫を抱え、アイレムと社名変更しても経営状態は厳しいままでした。そこで、1983年に辻本を含む3人が退社し、10億円の負債を支払いながら新たな会社を設立することになります。タイトー社長のコーガンから1億5千万円を借りて、カプコンを設立しました。カプコンはオリジナルゲームを目的に設立されましたが、当初はエレメカ（メダルゲーム）で参入し、1984年に業務用縦スクロールシューティングゲーム『バルガス』を発売します。その後、コナミからの転職組藤原得郎、岡本吉起らにより、名作が開発され、ゲーム会社としての知名度を上げました。経営的には火の車でしたが、数度の経営危機を乗り越え、数多くのヒット作を生み出しています。社内の世代交代のサイクルが早いのも特徴です。', 'capcom', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (16, 'コナミ', 'コナミ', 'コナミグループ株式会社は、日本の企業で、ゲームソフトやアミューズメント機器、スポーツクラブの運営を行っている純粋持株会社である。創業は1969年で、アーケードゲーム事業に参入する前はジュークボックスのレンタルと修理業を行っていました。その後、MSX、ファミリーコンピュータ、プレイステーションなどのパソコン･家庭用テレビゲーム機で、多岐にわたるジャンルの人気ゲーム作品を発表し、現在ではテレビゲームに留まらず、ソーシャルゲーム、カードゲームなどの玩具の製作・発売、スポーツクラブの運営など多角的に事業を展開しています。東京証券取引所プライム市場、ロンドン証券取引所に上場し、日経平均株価（日経225）構成銘柄の一つです。コナミグループは、1980年代にアーケードゲームから家庭用コンピューターゲームへ参入した老舗ゲームメーカーの中でも、現在も独立を保っている数少ない企業の一つです。', 'konami', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (17, 'スクウェア', 'スクウェア', 'スクウェアは、以前は日本のコンピュータゲームソフト会社で、ファミリーコンピュータ ディスクシステム向けソフトを開発していました。同社の代表的な作品には、エニックス（現スクウェア・エニックス）が発売した『ドラゴンクエストシリーズ』と並び、日本のコンピュータRPGの代表的な作品とされる『ファイナルファンタジーシリーズ』があります。2003年にエニックスと合併し、スクウェア・エニックスとなりました。', 'suqare', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (18, 'ナムコ', 'ナムコ', '1955年に中村雅哉氏が有限会社中村製作所を設立し、1971年にはnamcoブランドを開始しました。そして1977年6月1日には、ナムコという社名に変更しました。当時の英語名は「NAMCO LIMITED」でした。その後、2005年6月25日の第50回定時株主総会でナムコとバンダイの経営統合の議案が可決承認され、上場会社としてのナムコは9月29日に幕を下ろし、株式会社バンダイナムコホールディングスの子会社となりました。これにより、ナムコはバンダイナムコグループの中で組織的に統合され、現在も世界中でゲームやアミューズメント施設を運営しています。', 'namco', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (19, 'ポケモン', 'ポケモン', '', 'pokemon', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (20, 'スクウェア・エニックス', 'スクウェアエニックス', '株式会社スクウェア・エニックスは、日本のゲームソフト販売・開発会社であり、出版社でもあります。2003年に、ゲームメーカーのスクウェアとエニックスが合併し、誕生しました。合併には様々な理由がありますが、主には、両社のコンテンツ資産の有効活用による相乗効果を図るため、オンラインゲームやモバイルゲームの時代に備えるため、発売スケジュールの調整で『ドラゴンクエストシリーズ』と『ファイナルファンタジーシリーズ』を衝突させないことで収益機会を拡大するためなどがありました。現在、スクウェア・エニックスは、世界的に有名なゲームソフトを多数手がける大手企業として知られています。', 'square-enix', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (21, 'コーエー', 'コーエー', '株式会社コーエーは、パソコンゲームや家庭用ゲーム機のゲームソフトを開発する日本の企業でした。創業は1978年で、元々は染料や工業薬品の問屋でしたが、1980年に創業者がゲーム開発に興味を示し、業種転換をしました。同社は、『信長の野望』をはじめとする歴史シミュレーションゲームで有名で、国産非アダルトPCゲームメーカーとして25年以上にわたって提供を続けました。1994年には女性向け恋愛シミュレーションゲーム『アンジェリーク』を世界初として発売しました。2009年には同業のテクモと経営統合を行い、コーエーテクモホールディングスを設立しました。2010年にはテクモを吸収合併し、コーエーテクモゲームスとなりました。', 'koei', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (22, 'AQインタラクティブ', 'エーキューインタラクティブ', '', 'aq', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (23, 'バンダイナムコゲームス', 'バンダイナムコゲームス', '2005年6月25日、ナムコとバンダイの経営統合が可決承認され、ナムコは上場会社から退き、バンダイナムコホールディングスの子会社となった。2006年3月31日にはバンダイのゲーム部門をバンダイナムコゲームスに統合し、明確な立場を示した。2008年4月1日にはバンプレストのゲーム事業を譲受し、バンプレストレーベルを新設した。2009年4月1日にバンダイナムコグループにおけるモバイルコンテンツを自社管轄にし、公式サイトを統合した。そのため、バンダイとバンプレストの知的財産権が自社に移行され、自社の管轄に移動された。また、サイト統合後もレーベル自体は統合されず、各レーベルのロゴマークを使い分けていたが、2014年4月1日以降に発売されるソフトについては各レーベル表記を廃し、完全にバンダイナムコゲームスレーベルに統合された。', 'bandainamcogames', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (24, 'バンダイナムコエンターテインメント', 'バンダイナムコエンターテインメント', '株式会社バンダイナムコエンターテインメントは、日本の企業で、コンシューマーゲームなどのゲームソフトの制作および開発を行っています。旧ナムコを母体としており、バンダイナムコホールディングスの完全子会社で、中核企業の一つです。略称は「BNEI」「バンナム」です。2015年4月1日に社名をバンダイナムコゲームスからバンダイナムコエンターテインメントに変更し、現在はコンシューマーゲーム、携帯電話コンテンツの開発、販売に専念しています。また、2022年4月1日には、バンダイナムコグループの再編とロゴマークの変更に伴い、社名の英文表記とロゴマークが変更されました。略称の「バンナム」は、同社のゲーム内にも登場しており、以前は「バムコ」という名称が用いられていました。', 'bannam-entertainment', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (25, 'セガサミー', 'セガサミー', 'セガサミーホールディングスは、パチスロ、パチンコ、ゲームメーカーのサミーとゲームメーカーのセガを買収した後、2004年に設立された持株会社です。東京証券取引所に上場しています。2014年以降、グループの再編成が実施され、セガサミーホールディングスは中間持株会社のセガホールディングスを子会社としています。また、2018年にはグループ経営の強化のために再編成され、セガサミーホールディングスに管理機能やライセンス機能が集約されました。2021年には、サミーとセガグループの一部の管理業務を譲受したことが発表されました。', 'sega-sammy', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (26, 'マーベラスエンターテイメント', 'マーベラスエンターテイメント', '1997年に中山晴喜氏が、セガ・エンタープライゼスのキャラクター部で商品化獲得営業をしていた経験を生かして、キャラクター資産を活用したビジネスを行う目的で株式会社マーベラスエンターテイメントを設立しました。2011年には、中山隼雄氏が設立したAQインタラクティブとライブウェアの2社を吸収合併し、商号を株式会社マーベラスAQL（マーベラスエーキューエル）に変更しました。そして、2014年には現在の社名である株式会社マーベラスに変更し、「驚き」と「感動」を世界に届ける新しいエンターテイメントを創造することを経営理念としています。', 'marvelous-e', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (27, 'マーベラス', 'マーベラス', '株式会社マーベラスは、日本の東京都品川区東品川に本社を置く、オンラインゲーム、ゲームソフト、アニメソングの企画、制作、販売を主な事業内容とする企業であり、同社のレコードレーベルでもある。知的財産権を活用した幅広いコンテンツの創出・制作を得意としており、東京証券取引所プライム市場上場企業である。1997年に設立され、2011年にAQインタラクティブとライブウェアの2社を吸収合併し、商号をマーベラスAQLに変更し、2014年に社名を現在の株式会社マーベラスに変更した。マーベラスの経営理念は、『「驚き」と「感動」を世界に届ける新しいエンターテイメントの創造』である。また、同社のCD・DVDのパッケージには「MARVELOUS!」と表記されている。', 'marvelous', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (28, 'アガツマ', 'アガツマ', 'アガツマは、東京都台東区に本社を置く玩具メーカーで、ピノチオ・ビッグベン・ダイヤペットブランド名の玩具を販売しています。主に幼児・女児向けの玩具を得意としており、男児向け玩具は比較的少なめです。売上の8割がアンパンマンで、アンパンマン会議ではリーダー的な存在となっています。かつてはアガツマ・エンタテインメントという子会社でゲームメーカーも行っていましたが、経営悪化のため2015年12月に解散しました。', 'agatsuma', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (29, 'ロケットカンパニー', 'ロケットカンパニー', 'ロケットカンパニーは、家庭用ゲーム機や携帯ゲーム機事業を展開するために1998年に設立された、日本のゲーム制作会社でした。親会社のイマジニアの子会社で、イマジニアが携帯電話向けゲーム事業に特化するため、非ゲーム系のソフトを開発、販売していたことがあります。代表的な作品として、ゲームボーイ向けの『合格ボーイ』の元となった『漢検DS』や、チョビぐるみシリーズ、『メダロットDS』などがありました。しかし、2016年7月1日に親会社のイマジニアへ吸収合併され解散しました。', 'rocketcompany', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (30, 'アトラス', 'アトラス', '', 'atlus', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (31, 'NECアベニュー', 'エヌイーシーアベニュー', 'NECグループのレコード会社であるNECアベニュー株式会社は、ビデオソフトやゲームソフトの開発・販売を手がけていた。1987年に設立され、初期はアーケードゲーム移植を行っていたが、後にパソコンの美少女ゲーム移植も手がけた。レコード会社としてはゲームミュージックのサウンドトラックを発売し、アイドル歌謡やニューミュージックの楽曲もリリースした。1995年にゲームソフト・周辺機器の開発事業を新会社・NECインターチャネルに移管し、1998年に全ての活動を停止。ただし、関連会社のNECアベニュー音楽出版は現在も存続している。楽曲の一部は「アベニューノアールレーベル」名義で発売され、クラシック音楽の音源についても再発された。', 'nec-abenue', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (32, 'コンパイル', 'コンパイル', '株式会社コンパイルは、かつて日本で活躍したゲームソフト開発会社です。広島県広島市南区大須賀町に1982年に設立され、1990年代には『ぷよぷよ』のヒットで有名になりました。しかし、経営破綻により2002年に解散し、消滅しました。経営破綻後、コンパイルの流れを汲む企業にIPが引き継がれました。コンパイルという名前は、「ビデオゲームにとどまらず、将来はなんでも編集や作成のできる会社になりたい」という目標から名付けられました。また、『ぷよぷよ』は、1990年代に全盛だった落ち物パズルゲームの一つとして、予想を超える大ヒット作品となりました。', 'compile', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (33, 'NECインターチャネル', 'エヌイーシーインターチャネル', '株式会社インターチャネルは、エンタテインメントコンテンツソフトウェアの企画・販売を行う会社です。株式会社インデックス・ヴィジュアルアンドゲームズと株式会社インターチャネル・ホロンが合併し、インターチャネルになりました。会社名は、『interactive』（双方向）と『channel』（経路）を組み合わせた造語で、旧社名に含まれていた「ホロン」は物の構造を表す概念という意味です。かつては、アダルトゲームをはじめ各種コンピュータゲームから家庭用ゲームへの移植、海外ゲームタイトルの国内移植、教育ソフト、ユーティリティソフトの販売や携帯電話向けサイトの運営を行っていましたが、現在は映像作品の企画・製作・販売が主な業務となっています。また、インターチャネルはインデックスグループの中間持株会社であり、コンピュータソフトや映像ソフトを統括しています。', 'nec-inter-channel', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (34, 'アルケミスト', 'アルケミスト', '下記の文章を丁寧語表現で300文字以内にわかりやすくまとめてください。\r\n', 'alchemist', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (35, 'ゲームアーツ', 'ゲームアーツ', '「株式会社ゲームアーツ」は、日本のゲームソフトウェア制作会社で、1985年に設立されました。PC-8801mkII SRを提供されたことにより、1985年4月にアクションシューティングゲーム『テグザー』を発売し、海外でも人気がありました。その後も、『ファイアーホーク』や『シルフィード』などをリリースし、プログラム技術を駆使したゲーム制作で有名になりました。1990年12月には自社でメガドライブ版『ぎゅわんぶらあ自己中心派 片山まさゆきの麻雀道場』を発売し、コンシューマゲーム市場への参入を果たしました。以降、セガのゲーム機向けにゲームソフトをリリースし、有力サードパーティーの地位を確立しました。2005年にはガンホー・オンライン・エンターテイメントの連結子会社となり、オンラインゲームの開発を行っています。また、『大乱闘スマッシュブラザーズX』の開発にも多数のスタッフが参加しました。', 'gamearts', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (36, '角川書店', 'カドカワショテン', '「角川書店」は、日本の出版社・KADOKAWAのブランドの一つで、1945年に国文学者の角川源義によって創業されました。創刊時には、佐藤佐太郎歌集「歩道」を出版し、1949年には「角川文庫」を創刊し、1952年には「昭和文学全集」の成功によって文芸出版社としての地位を確立しました。1970年代には角川文庫を横溝正史を初めとする一般大衆向けに路線転換し、書籍を映画化しテレビコマーシャルを利用したメディアミックス戦略を成功させ、映画界に角川映画旋風を巻き起こしました。2003年には持株会社制度に移行し、角川ホールディングスに社名変更して純粋持株会社となりました。また、角川書店は、事業再編の一環として、角川映画、富士見書房、角川ザテレビジョン、角川クロスメディアなど、様々な分野に分社化されました。', 'kadokawa', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (37, 'ガスト', 'ガスト', 'ガストは、コーエーテクモゲームスのゲームソフトブランドであり、エンタテインメント事業部に属する5つのブランド別組織の一つです。主な作品に、ロールプレイングゲーム「アトリエシリーズ」があります。1993年に創業され、最初はパーソナルコンピュータ（PC）でのゲームソフト開発からスタートしました。その後、家庭用ゲーム機での開発にシフトしていき、1997年に発売された「マリーのアトリエ 〜ザールブルグの錬金術士〜」はヒットしてシリーズ化されました。2011年には、同社の作品においてCEROレーティングにおける審査に不適切な箇所があったことが問題となりましたが、コーエーテクモグループの完全子会社となり、ガストブランドは継続されました。', 'gust', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (38, 'アートディンク', 'アートディンク', '株式会社アートディンクは、1986年に設立された日本の企業で、主にコンピューターゲームの開発や販売を行っています。本社は東京都中央区月島にあり、シミュレーションゲームを得意とし、『A列車で行こう』『Neo ATLAS』『カルネージハート』シリーズなどが主力商品です。国内トップシェアを誇る老舗メーカーであり、PCや家庭用ゲーム機を問わず様々なハードに多くのタイトルを提供し続けています。また、受託開発や移植などのデベロッパー業務も行っています。社名の由来は、4人の創業者のイニシャルから来ており、元々はPC用のゲームを作るつもりはなかったが、試しに出して評判が良かったため、会社設立することになったとのことです。', 'artdink', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (39, 'アスミック・エース', 'アスミック・エース', 'アスミック・エース株式会社は、日本の中堅映画会社で、海外映画の買い付けや版権管理、ビデオ（DVD）ソフトの販売などを行っています。以前はゲームソフト開発・販売も行っていました。略称は「アスミック」、「AA」、「AAI」、「アスエー」です。1981年に株式会社ヘラルド・エースを設立し、1985年にアスク・住友商事・講談社が共同で株式会社アスミックを設立しました。1998年には住友商事子会社の株式会社アスミックと角川書店子会社の株式会社エースピクチャーズが合併し、アスミック・エースエンタテインメント株式会社が設立されました。2012年には、住友商事が当社を完全子会社化の上、全株式をジュピターテレコム（J:COM）に売却し、社名をアスミック・エース株式会社と改めています。', 'asmik', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (40, 'テクモ', 'テクモ', 'テクモ株式会社は、かつて存在した日本のコンピュータゲームソフト開発会社でした。家庭用ゲームソフトや業務用ソフト、オンラインゲーム、モバイルコンテンツの開発を行っていました。2010年にコーエーと合併して、コーエーテクモゲームスとなりました。社内では、社長の退任や訴訟が相次ぎ、M&Aの絶好のチャンスでどの会社に買収されてもおかしくない状況でした。しかし、スクウェア・エニックスの株式公開買い付け提案には非賛同し、代わりにコーエーとの経営統合への協議を開始し、2009年にコーエーテクモホールディングスを設立しました。', 'tecmo', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (41, 'アスキー', 'アスキー', 'アスキーは、かつて存在したコンピュータ関連の雑誌や書籍を出版していた日本の出版社です。1977年に設立され、『月刊アスキー』などを発行していました。1986年には、パソコンソフトなどの卸売会社「ソフトウィング」を設立しましたが、1994年にカテナに吸収合併されました。1991年には、出版を主軸とした慎重経営を主張した郡司と塚本が退社し、塚本はインプレスを設立しました。1998年にはCSK、2001年にはユニゾン・キャピタルから経済的支援を受けました。2002年にアストロアーツが商号を変更し、アスキーとなりました。現在は、KADOKAWAグループに吸収され、角川アスキー総合研究所の事業ブランドとしてコンピュータ関連の出版事業を引き継いでいます。', 'ascii', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (42, 'ディースリー・パブリッシャー', 'ディースリーパブリッシャー', 'ディースリー・パブリッシャーは、東京都千代田区神田神保町に本社を置くゲームソフトパブリッシャーで、バンダイナムコグループに属しています。元々はカルチュア・コンビニエンス・クラブの関連企業であるカルチュア・パブリッシャーズ株式会社のゲーム事業部でしたが、親会社の方針で整理されることになりました。そこで伊藤裕二がゲーム部門をマネジメント・バイアウトし、株式会社ディースリー・パブリッシャーを独立させました。2010年には、親会社であるディースリーと合併し、新ディースリー・パブリッシャーとして再編されました。同社は、廉価なSIMPLEシリーズのゲームソフトやパチスロソフト、ディズニー映画のゲーム化、乙女ゲームなど、様々なゲームソフトを展開しています。', 'd3publisher', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (43, 'ESP', 'イーエスピー', 'ESPはかつて存在した日本のコンピューターゲーム会社で、Entertainment Software Publishingの略称です。1997年に中堅ゲーム会社の技術交換ネットワークであるGD-NETを母体に設立されました。当時の出資会社はGD-NET加盟の13社で、宮路洋一が社長を務めました。ESPの設立背景には、制作費の高騰による負担と共通の資金調達窓口の必要性と、セガサターン陣営の苦境がありました。ESPは、オリジナル作品をサターンプラットフォームで供給する方針を示し、『グランディア』、『機動戦士ガンダム ギレンの野望』、『バロック』などの話題作をリリースし、ドリームキャスト、PlayStation 2にも展開しました。しかし、セガが撤退し、CSKグループもセガの売却に動いたため、2002年にゲームアーツが全株式を買収し、ESP名義でのゲーム制作を開始しました。2006年にはディースリー・パブリッシャーが全株式を買収し、子会社化し、2010年にディースリー及びディースリー・パブリッシャーと合併しました。', 'esp', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (44, '5pb.', 'ファイブピービー', '株式会社MAGES.が展開していたブランド名「5pb.」は、音楽レーベル「5pb.Records」とゲームブランド「5pb.Games」を指していた。かつては会社名だったが、2011年にドワンゴと文化放送の合弁会社であるAG-ONEと合併し、5pb.は解散し、MAGES.を発足した。その後も「5pb.」はブランド名として使用され、関連作品には社名を表記していないことが多かった。2019年7月にMAGES.は独立を発表し、「5pb.」ブランドをMAGES.本体に統合することが発表された。現在は対外的な名義は基本的に「MAGES.」としているが、5pb.の公式サイトを使用し続けており、5pb.Records・5pb.Gamesのロゴも残されている。', '5pb', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (45, '日本ファルコム', 'ニホンファルコム', '日本ファルコム株式会社は、日本のゲームソフト開発・販売企業であり、ドラゴンスレイヤーシリーズ、イースシリーズ、英雄伝説シリーズが主な作品です。1981年に創業し、2001年に現在の法人となり、2003年に東京証券取引所マザーズに上場しました。社名は「ミレニアム・ファルコン号」から着想を得て、「com」を合成しています。ファルコムはパソコンゲーム黎明期のメーカーであり、非成人向けゲームを中心に扱っていましたが、2000年代後半にPSPへ参入し、家庭用ゲーム機向けが中心になりました。ゲームミュージックにも力を入れており、「ファルコム音楽3原則」という考え方があります。1988年には「ファルコムレーベル」を発足し、自社のゲームミュージック作品をリリースしています。また、ゲームを起動すると紫色・黄色・黄緑色・水色の四角形からFalcomのロゴに変化するムービーは、新海誠氏のデザインです。', 'nihon-falcom', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (46, 'アクワイア', 'アクワイア', 'ACQUIRE株式会社は、日本の秋葉原に本社を構え、家庭用ゲームの開発を主に手掛けている会社です。1994年に設立され、その後法人化して現在に至っています。同社の方針は、「独自性」と「奇抜さ」をキーワードに、常識にとらわれないコンテンツの開発を目指しています。主な事業は家庭用ゲームソフトや業務系システムの開発で、最近ではスマートフォンアプリの開発も行っています。同社は、自社で所有するモーションキャプチャースタジオ「Studio Acquire」の運営事業も行っており、自社開発の3Dアクションゲームの制作に利用されています。ACQUIREの作品は、和風ゲームを得意としており、『立体忍者活劇 天誅』、『剣と魔法と学園モノ。』、そして2018年に開発された『OCTOPATH TRAVELER』などが人気を博しています。', 'acquire', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (47, 'プロトタイプ', 'プロトタイプ', 'PROTOTYPE株式会社は、日本のゲーム会社であり、コンピュータエンターテインメント協会の正会員です。この会社は、元インターチャネル（旧NECインターチャネル〈NEIC〉）のプロデューサーである多部田俊雄氏によって2006年に設立されました。主にビジュアルアーツで発売されたアダルトゲームの家庭用ゲーム機移植作品を中心に発売しており、携帯電話向けコンテンツ「ビジュアルアーツ★Motto」の運営も行っています。また、フロントウイングと協力関係にあり、「グリザイアシリーズ」のテレビアニメ版では提供企業に名を連ねています。', 'prototype', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (48, '日本一ソフトウェア', 'ニッポンイチソフトウェア', '日本一ソフトウェアは、日本の企業で、岐阜県各務原市に本社を置く。主な事業は、コンピューターソフトウェアの開発、製造、販売である。元サン電子スタッフの北角浩一らによって1991年に設立され、1994年に社名を有限会社日本一ソフトウェアに変更した。2003年に本社を岐阜県各務原市那加雄飛ケ丘町に移転し、2008年に現在の場所である蘇原月丘町に移転した。2012年には、設立20周年を迎える2013年までを「日本一ソフトウェア20周年祭」とし、様々なイベントや新作の発売を行った。同年、大阪市に大阪開発室を開設した。また、同社は、シミュレーションRPGの発売数が最も多いとしてギネス世界記録に認定された。さらに、同社のゲームキャラクターであるプリニーが、プロサッカークラブFC岐阜のスタジアム応援キャラクターとして登場している。', 'nippon-ichi-soft', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (49, 'レベルファイブ', 'レベルファイブ', '「株式会社レベルファイブ」とは、日本のゲームソフトの企画、開発、制作、販売を行う企業で、社名は五つ星＝最上級のクオリティから来ています。1998年に元リバーヒルソフト社員の日野晃博を中心に設立され、SCEの支援を受けながら、『ダーククラウド』『ドラゴンクエストVIII』『ローグギャラクシー』『JEANNE D''ARC』などのRPG作品を開発しました。2006年にパブリッシング事業を開始し、『レイトン教授と不思議な町』がヒット。以降、『イナズマイレブン』や『妖怪ウォッチ』では玩具メーカーとの提携を深め、販促活動に注力しています。また、アニメ映画やテレビアニメの制作にも力を入れ、メディアミックス展開を積極的に活用しています。', 'level5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (50, 'バンダイナムコ', 'バンダイナムコ', '2005年6月25日、ナムコとバンダイの経営統合が可決承認され、ナムコは上場会社から退き、バンダイナムコホールディングスの子会社となった。2006年3月31日にはバンダイのゲーム部門をバンダイナムコゲームスに統合し、明確な立場を示した。2008年4月1日にはバンプレストのゲーム事業を譲受し、バンプレストレーベルを新設した。2009年4月1日にバンダイナムコグループにおけるモバイルコンテンツを自社管轄にし、公式サイトを統合した。そのため、バンダイとバンプレストの知的財産権が自社に移行され、自社の管轄に移動された。また、サイト統合後もレーベル自体は統合されず、各レーベルのロゴマークを使い分けていたが、2014年4月1日以降に発売されるソフトについては各レーベル表記を廃し、完全にバンダイナムコゲームスレーベルに統合された。', 'bandainamco', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (51, 'エクシング', 'エクシング', '株式会社エクシングは、通信カラオケ業界でJOYSOUNDやUGAの運営を主に行う会社で、ブラザー工業グループに属し、本社は愛知県名古屋市瑞穂区桃園町にあります。1992年に設立され、JOYSOUNDの企画・開発や携帯電話用コンテンツの企画・制作・配信などを行っています。かつてはカラオケボックス「JOYSOUND直営店」や飲食店の運営も行っていましたが、現在は子会社のスタンダードに移管されています。また、1990年代半ばから2000年代初頭には、エクシング・エンタテイメントというブランド名で家庭用ゲーム機向けにゲームソフトの開発・発売も行っていました。さらに、ブラザー工業のパソコンソフト自動販売機の通信システム事業も引き継いでいました。', 'xing', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (52, 'マーベラスAQL', 'マーベラスエーキューエル', '株式会社マーベラスは、日本の東京都品川区東品川に本社を置く、オンラインゲーム、ゲームソフト、アニメソングの企画、制作、販売を主な事業内容とする企業であり、同社のレコードレーベルでもある。知的財産権を活用した幅広いコンテンツの創出・制作を得意としており、東京証券取引所プライム市場上場企業である。1997年に設立され、2011年にAQインタラクティブとライブウェアの2社を吸収合併し、商号をマーベラスAQLに変更し、2014年に社名を現在の株式会社マーベラスに変更した。マーベラスの経営理念は、『「驚き」と「感動」を世界に届ける新しいエンターテイメントの創造』である。また、同社のCD・DVDのパッケージには「MARVELOUS!」と表記されている。', 'marvelousaql', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (53, 'アークシステムワークス', 'アークシステムワークス', 'アークシステムワークス株式会社は、日本のゲームソフトウェア制作会社で、家庭用ゲームソフトやアーケードゲームの企画、制作、販売を行っています。1991年に現在の社名に変更し、『ギルティギアシリーズ』をはじめとする2D対戦格闘ゲームの開発で知られています。また、格闘ゲームに関するイベントも主催しています。『GUILTY GEAR Xrd -SIGN-』では注目を集めたアニメーション技術を採用しており、ダウンロードゲームにも取り組んでいます。2015年には、旧テクノスジャパンや旧ワークジャムの無体財産権を譲受しました。また、韓国にアジア支店を設立しています。定期的にゲーム紹介や社内大会を配信するため、ニコニコチャンネル、Twitch、Youtubeにチャンネルを開設しています。', 'ark-system-works', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (54, 'コーエーテクモゲームス', 'コーエーテクモゲームス', '「株式会社コーエーテクモゲームス」は、神奈川県横浜市西区に本社を置く、日本のゲームソフト販売・開発会社であり、コーエーテクモホールディングスの子会社です。パソコンおよび家庭用ゲーム機用のゲームソフトやオンラインゲーム、モバイルコンテンツの企画・開発を統括し、パブリッシャー機能、関連書籍の出版事業も行っています。また、開発子会社を中華人民共和国（天津・北京）、シンガポール、ベトナムに置いています。2014年には、子会社である「ガスト」を吸収合併し、ガスト長野開発部を設立しました。2020年3月には、本社を横浜市港北区箕輪町から同市西区みなとみらいのKTビル内に移転しています。', 'koei-tecmo', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (55, 'アイデアファクトリー', 'アイデアファクトリー', 'アイディアファクトリー株式会社は、日本のゲーム会社であり、コンピュータエンターテインメント協会の正会員です。1994年に、データイースト出身の桑名真吾氏によって設立され、主にコンシューマーゲームやアーケードゲームの開発・販売を行っています。', 'idea-factory', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (56, 'アクアプラス', 'アクアプラス', 'アクアプラスは、日本のゲーム会社であり、HIKEの子会社である。コンピュータエンターテインメントレーティング機構、コンピュータソフトウェア倫理機構の正会員である。家庭用やPC向けに一般向けのAQUAPLUSブランドや、アダルトゲームブランドであるLeafを展開している。音楽関連事業や飲食店事業も手掛けている。2022年12月まではユメノソラホールディングスの子会社であり、2022年12月28日からはポールトゥウィンホールディングスの子会社であるHIKEの子会社になる。', 'aquaplus', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (57, 'コンパイルハート', 'コンパイルハート', '株式会社コンパイルハートは、日本のゲーム会社であり、アイディアファクトリー株式会社の子会社です。2010年10月28日以降、D4エンタープライズから、かつて存在したゲームメーカー「コンパイル」の『ぷよぷよ』シリーズを除くコンシューマゲームソフトの営業権を取得しています。\r\n\r\n同社の主な作品には、『ネプテューヌシリーズ』、『アガレスト戦記』シリーズ、『圧倒的遊戯 ムゲンソウルズ』シリーズなどがあります。また、2018年にはバーチャルYouTuberのいるはーとの開発にも携わっていました。\r\n\r\n創業時には、旧コンパイルやアイキの代表を務めた仁井谷正充を起用してゲームの監修を行っていましたが、2006年に監修契約を解除し、同社の商品と仁井谷との関係は一切無くなりました。なお、仁井谷はその後独自にコンパイル丸を2016年に設立しています。\r\n\r\nコンパイルハートは、2010年10月28日にD4エンタープライズから、旧コンパイルが製作販売を行ったコンシューマゲームソフト全般の営業権を取得し、「旧コンパイルの版権を活かした展開を行う」との発表を行いました。ただし、セガが権利を保有するパズルゲーム『ぷよぷよ』シリーズ、有限会社エムツーが権利を保有するシューティングゲーム『アレスタ』シリーズは取得対象に含まれていないとされています。', 'compile-heart', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (58, 'フリュー', 'フリュー', 'ル機やプライズの製造販売、スマートフォン向けアプリを中心とした若年層向け携帯コンテンツの作成・運営、家庭用ゲーム事業、映像コンテンツの製作等を行っています。同社のスローガンは「Precious days, always」となっています。\r\n\r\nフリュー株式会社は、オムロンの100%出資子会社だった旧オムロンエンタテインメント株式会社（略称OJE）がマネジメント・バイ・アウト方式により2007年4月1日に設立されました。この際、フリューHDに全事業を譲渡し、同時にフリューHDはフリューに社名変更し、株式会社ウィーヴと資本・業務提携を行いました。本社所在地は東京都渋谷区鶯谷町で、かつては愛知県一宮市に本社を構えていましたが、現在は一宮事業所となっています。\r\n\r\nフリューの社名の由来は「風流」から来ており、「風流」とは、みやびやかなものや風情のあるものを指す言葉です。また、中世には「ふりゅう」と読んで、人の目をぱっと引く風情あるつくりもの、祭礼に出るきらびやかな練りもの、あるいは美しい踊りを指す言葉でした。フリューはこの「風流」という言葉が本来持つエンタテインメントの美意識を表現し、「人びとの心を豊かで幸せにする良質なエンタテインメントを創出する!」を企業理念としています。', 'furyu', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (59, 'dramaticcreate', 'ドラマティッククリエイト', 'HuneX株式会社は、1992年にNECホームエレクトロニクスとヒューマンの子会社として設立され、家庭用テレビゲームの開発に従事しています。当初は、PCエンジン用ゲームソフトの開発を手がけていましたが、その後PC-FXで発表した『ブルーブレイカー 〜剣よりも微笑みを〜』、『ファイアーウーマン纏組』、『ファーストKiss☆物語』によって、人気ギャルゲームメーカーとしての地位を確立しました。しかし、『夏色Celebration』以降はヒット作を生み出せず、移植ゲームの開発に主力を置くようになりました。その後、ディースリー・パブリッシャーからリリースされた低価格ゲームシリーズ「SIMPLEシリーズ」の開発元として、バーチャルアイドル「双葉理保」を登場させ、「乙女的恋革命★ラブレボ!!」や「硝子の森」などの乙女ゲームメーカーとして知名度を上げました。\r\n\r\nHuneXは、自社ブランドではなく、アルケミスト、ディースリー・パブリッシャーなどの別ブランドでの発表が9割以上を占めています。現在、HuneXは、「dramatic create（ドラマティック クリエイト）」ブランドでの展開も行っており、ゲーム作品の移植を通じて、PCゲームよりも快適なプレイ環境を提供しています。', 'dramaticcreate', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (60, 'アガツマ・エンタテインメント', 'アガツマエンタテインメント', 'アガツマ・エンタテインメントとは、かつて東京都台東区浅草橋にあった、コンピュータゲーム制作会社でした。この会社は、おもちゃメーカーのアガツマの関連会社であり、主に幼児向け知育ゲームを制作していました。また、海外のゲーム会社とのエージェント業務も手掛けていました。例えば、ニンテンドー3DS専用ソフト『CODE OF PRINCESS』など、コアゲーマー向けのゲームも販売していました。\r\n\r\nしかし、アガツマ・エンタテインメントは、経営状態が悪化し、2015年12月11日に解散することになりました。その後、2016年3月31日に清算手続が終了しました。商品に関する問い合わせや不具合対応については、親会社である株式会社アガツマが対応することになっています。', 'agatsuma-e', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (61, 'ガンホー・オンライン・エンターテイメント', 'ガンホーオンラインエンターテイメント', 'ガンホー・オンライン・エンターテイメント株式会社は、オンラインゲームの運営を行う企業で、本社は東京都千代田区にあります。1998年にアメリカの大手オークションサイトOnSaleとソフトバンクの合弁企業であるオンセール株式会社として設立されました。当初はネットオークション事業を手がけましたが、Yahoo!オークション等の大手オークションサイトの牙城を崩すまでには至らず、2002年に同事業からは撤退し、韓国のゲーム会社グラビティより『ラグナロクオンライン』の国内運営権を獲得し、オンラインゲーム運営事業へと転換しました。以降、『A3』・『ポトリス』などの運営も請け負っており、オンラインゲームを総合的に運営するようになりました。2004年事業年度には、『ラグナロクオンライン』のヒットにより、売上高は約42億円と急成長を遂げ、Fast50において1位を受賞し、Fast500においても10位を受賞しました。その後も積極的に提携やM&A等を進め、2006年にはカジュアルゲームやブログ、ネットニュースなどを統合したポータルサイト「ガンホーゲームズ」を展開しました。2012年にリリースしたスマートフォン・タブレット向けゲーム「パズル&ドラゴンズ」が大ヒットし、モバイル部門の売り上げで急成長しました。', 'gungho', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (62, 'El Dia', 'エルディア', '', 'eldia', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (63, 'スパイク・チュンソフト', 'スパイクチュンソフト', '株式会社スパイク・チュンソフトは、日本の会社で、主な事業内容はゲームコンテンツの企画、開発、販売、運営です。スパイク・チュンソフトは、ドワンゴの完全子会社であり、KADOKAWAの連結子会社です。\r\n\r\n2005年から、スパイク・チュンソフトはドワンゴの傘下にあり、直接の親会社は中間持株会社のゲームズアリーナでした。2012年4月1日に、旧チュンソフトの創業者である中村光一氏が新会社の会長、旧スパイク社長の櫻井光俊氏が同じく新会社の社長に就任し、チュンソフトを存続会社としてスパイクを吸収合併しました。\r\n\r\n2013年1月7日には、ドワンゴ子会社の株式会社ティーアンドイーソフトを吸収合併しました。また、2017年12月には、アメリカ合衆国カリフォルニア州に子会社「SPIKE CHUNSOFT, INC.」を設立しました。\r\n\r\n2021年3月31日には、新設分割により遊技機およびゲーム等デジタルコンテンツに関する事業を株式会社フォーチュンに継承しました。そして、2021年7月1日には、株式会社マイクロビジョンの開発受託事業を継承しました。', 'spike-chunsort', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (64, '角川ゲームス', 'カドカワゲームス', '株式会社角川ゲームスは、角川グループの一員として、各傘下企業が独自にゲームソフトの開発・販売を手がけていたため、グループ内の連携を強化するために、2009年4月に設立されました。これにより、角川ゲームスはグループ内での連携強化、プロデュース力の強化、ゲーム化の推進、グループ外との連携、新しいゲーム市場の創造を目指しました。2016年4月には、中国と台湾のパブリッシャーと資本業務提携を行い、海外展開を狙いました。\r\n\r\nしかし、2022年5月には、社長と取締役が新たにDragami Gamesを起業し、従来の「角川ゲームス」ブランドで発売された約半数のタイトルの知的財産権が新会社へ移譲されることになりました。2022年7月1日には、一部の開発タイトルがDragami Gamesに移管され、角川ゲームスの規模は大幅に縮小され、公式ホームページから製品情報ページが削除されました。KADOKAWA主導で開発されたタイトルの発売元はKADOKAWAとなりましたが、「メタルマックス」シリーズは別の企業が発売権を取得しました。また、2022年には清算結了し、解散しました。', 'kadokawa-games', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (65, '3goo', 'スリーグー', '', '3goo', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (66, 'ACTIVISION', 'アクティビジョン', '', 'activision', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (67, 'インティ・クリエイツ', 'インティクリエイツ', '株式会社インティ・クリエイツは、主にゲームソフトの企画・開発を行うゲームメーカーでございます。この会社は、かつてカプコンに所属していたクリエイターたちが独立して設立したものでございます。\r\n\r\nこの会社は、横スクロールアクションゲームを得意としており、ロックマンシリーズの一つである「ロックマンゼロ」や、「クレヨンしんちゃんゲームシリーズ」などの下請けを受け持っているのが特徴です。最近では、アクションゲーム以外のジャンルにも携わり、「ぎゃる☆がんなど」のシューティングゲームや、「蒼き雷霆 ガンヴォルト」など自社オリジナルタイトルにも力を入れているのが特徴です。\r\n', 'inti', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (68, 'エンターグラム', 'エンターグラム', '', 'entergram', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (69, 'Studio Nanafushi', 'スタジオナナフシ', '', 'sutudio-nanafushi', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (70, 'ケムコ', 'ケムコ', '株式会社ケムコは、コトブキグループのゲーム部門・システム開発部門から分社化され、コンシューマーゲーム部門すなわち家庭用ゲームソフトやゲーム機用のアクセサリー類、周辺機器等の開発・製造・販売を受け継ぎました。所在地は東京都新宿区で、傘下に米国企業KEMCO U.S.A, INC.があります。ゲーム周辺機器で利益を上げていましたが、PS3時代になるとメモリーカードが廃止されるなどして収益が立たなくなり、家庭用ゲーム機向け事業は打ち切られました。その後携帯電話用ゲーム市場の拡大とともに、株式会社ケムコが受け継いでいた「ケムコ」ブランドは、コトブキソリューションに吸収され、現在は会社として休眠状態にあります。また、KEMCOの由来は、コトブキシステムのブランド名であり、コトブキシステムの母体であるコトブキ技研工業の英語名、"Kotobuki Engineering & Manufacturing Co., Ltd." の頭文字です。コトブキグループ内には、ゲーム以外にも介護用品や産業用機器を扱うケムコ商事など、ケムコの名を関する企業が存在しています。現在、株式会社ケムコのドメインもコトブキソリューションに譲渡され、寿グループにも株式会社ケムコの名前はなく、休眠状態にあります。', 'kemco', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (71, 'Warner Bros. Games', 'ワーナーブラザーズゲームス', 'Warner Bros. Games（旧Warner Bros. Interactive Entertainment）は、カリフォルニア州バーバンクに拠点を置くアメリカのビデオゲームパブリッシャーであり、Warner Bros. Discovery（WBD）のグローバルストリーミングおよびインタラクティブエンターテインメント部門の一部です。このパブリッシャーは、2004年1月14日にWarner Bros. Entertainmentの下でWarner Bros. Interactive Entertainmentとして設立され、同年10月に同社が設立された際にそのホームエンターテイメント部門に移管されました。Warner Bros. Gamesは、TT Games、Rocksteady Studios、NetherRealm Studios、Monolith Productions、WB Games Boston、Avalanche Software、WB Games Montréalなど、完全子会社のゲーム開発スタジオを管理しています。', 'WBG', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (72, 'アニプレックス', 'アニプレックス', 'アニプレックスは、日本のアニメーション制作会社であり、アニメーション作品や映像作品、ソーシャルゲームの企画、製作、販売、映画配給を主な事業としています。ソニー・ミュージックエンタテインメント（SMEJ）の完全子会社で、日本動画協会、日本映像ソフト協会、コンピュータエンターテインメント協会正会員です。1995年にSPE・ミュージックパブリッシングの商号で設立され、1997年にSMEJが資本参加し、2001年には完全子会社となり、商号も株式会社SME・ビジュアルワークスに変更されました。2003年にソニー・カルチャーエンタテインメントとして分離され、商号が株式会社アニプレックスに変更されました。アニプレックスは、当初はヒット作品がなく、苦境に陥っていましたが、サンライズのプロデューサーであった植田益朗を招き入れたことで回復し、2005年には東京都杉並区に「株式会社A-1 Pictures」を設立して実制作に進出しました。その後、スマートフォンアプリの開発にも進出し、2015年に配信された『Fate/Grand Order』は大ヒットを記録し、2017年3月期には売上高が1,000億円を超え、同社過去最高の大幅増益を果たしました。また、映画配給部門も有しており、アニメ作品のほか、実写映画やコンテンツリーグも手掛けています。', 'aniplex', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (73, 'フロム・ソフトウェア', 'フロムソフトウェア', 'FromSoftware株式会社は、日本のコンピュータゲームソフトの制作会社で、KADOKAWAの子会社です。1986年11月に設立され、当初は大型汎用コンピュータ向けのビジネスアプリケーションの開発を行っていました。その中には、豚の餌やり管理などの農業系アプリケーションも含まれていました。そのため、取引先の要求に応えるため、業界では珍しくスーツ姿で仕事をしていたと言われています。\r\n\r\n後にコンピュータゲーム業界へ参入し、1994年にプレイステーション用のゲームソフトウェア『キングスフィールド』を発売しました。その後、複数のプラットフォームでゲームソフトウェアを発売していきました。\r\n\r\nFromSoftwareのゲームソフトの特徴は、ストーリーや設定について多くを語らない傾向があります。そのため、ファンたちは自分で考察することが多く、"フロム脳"と呼ばれることがあります。\r\n\r\n2014年4月28日、KADOKAWAがFromSoftwareの株式を取得し、同社はKADOKAWAの子会社となりました。現在、FromSoftwareは、コンピュータゲームの開発に注力し、世界的に有名な作品を生み出しています。', 'from-software', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (74, 'Binary Haze Interactive', 'バイナリーハゼインタラクティブ', '', 'binary', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (75, 'ゲームアディクト', 'ゲームアディクト', '', 'gameaddict', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (76, 'Supergiant Games', 'スーパージャイアントゲームス', '', 'supergiant-games', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (77, 'ハチノヨン', 'ハチノヨン', '2005年に、源紘子とエレクトロニック・ゲーミング・マンスリー（EGM）の元編集者であるジョン・リカーディによって設立された企業が、"Enhance Games" です。2008年には、リチャルディと同じEGMの同僚であるマーク・マクドナルドが加わりました。しかし、2016年にマクドナルドはEnhance Gamesのビジネスおよび開発のヴァイスプレジデントとして別の企業に移り、退社しました。\r\n\r\nEnhance Gamesは、『モンスターハンター』、『ニーア』、『ドラゴンクエスト』、『ファイアーエムブレム』、『テイルズ』、『UNDERTALE』など、有名なゲームの知的財産権を使用し、契約条件で日本語から英語へ、また英語から日本語への翻訳とローカライゼーションを行っています。\r\n\r\n"Enhance Games" という名前の由来は、『スーパーマリオブラザーズ』の最終ステージの名前である "Enhanced Mode" からきています。この名前は、新しいステージに挑戦する前に、自分自身を強化することが重要であるという考えから着想を得て付けられたものです。', 'hatinoyon', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (78, 'サクセス', 'サクセス', '株式会社サクセスは、東京都品川区に本社を構えるコンピュータゲーム開発会社です。同社はスマートフォンやパソコン、ブラウザー、家庭用、業務用、オンラインなど、あらゆるプラットフォーム向けのアプリやゲームを手がけています。自社開発・販売のゲームに加え、大手からの受託開発や他社の開発ゲームのパブリッシングも行っており、作品数は非常に多いです。同社は、1983年に処女作「PLAY BALL」を発売以来、現在までに1600の開発タイトルをリリースし、世界のゲーム会社の中でもトップクラスの実績を誇っています。代表作には、シューティングゲーム『コットン』や、『おさわり探偵 小沢里奈』とそのスピンオフ作品『おさわり探偵 なめこ栽培キット』があります。\r\n\r\n同社は、開発ラインを支えるために、内製ツールの開発に力を入れており、社内業務改善を目的として開発した一部のツールをビジネスソフトとして外販しています。かつては、パチンコ・パチスロの企画・開発（主に受託開発）やアニメ製作事業も手がけていましたが、2022年には両事業を子会社「サクセスプラス」として分離しました。', 'saccess', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (79, 'イマジニア', 'イマジニア', 'イマジニア株式会社は、東京都新宿区に本社を置くコンテンツ提供会社です。社名は、「想像を形に変える者」を意味する造語であり、かつてはミサワホームホールディングスのグループ企業として設立され、「コンピュータ技術と融合する未来の住宅像」を研究するために活動していました。主にコンピュータゲームソフト制作を行っており、『銀河伝承』でファミリーコンピュータ市場に参入し、大人向けゲームや海外タイトルの移入に力を注いでいました。\r\n\r\nその後、1998年には子会社のロケットカンパニーを設立し、携帯電話を利用したコンテンツビジネスを主体に事業を展開してきました。しかし、2016年にロケットカンパニーを吸収合併し、再びコンシューマゲーム事業に参入しました。現在は、新しいコンシューマーゲームの開発に力を入れており、ニンテンドースイッチやスマートフォン向けのタイトルなど、様々なプラットフォームに展開しています。', 'imagineer', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `manufacturers` (`id`, `name`, `kana`, `overview`, `code`, `created_at`, `updated_at`) VALUES (80, 'SUPERDELUXE GAMES', 'スーパーデラックスゲームス', '', 'superdeluxegames', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);